def word_frequency(text: str) -> dict[str, int]:
    punctuation = '!\"#$%&\'()*+,-./:;<=>?@[\\]^_`{|}~'
    freq = {}
    for word in text.split():
        processed = word.strip(punctuation).lower()
        if processed:
            freq[processed] = freq.get(processed, 0) + 1
    return freq
